  "verses": [
    {
      "n": 27,
      "column": "left",
      "text": "dsihwotajeem nogurruschas Roh-\nkas/ tee bija baltgi/ un tappę"
    },
    {
      "n": 6,
      "column": "left",
      "text": "Kanna/ tee bija ką ta Sahle\nLauką/ un ką ta salta Sahle/\nttt ką tas Seens us Jumteem/\nkas fakalst/pirms tas eenahkahs."
    },
    {
      "n": 28,
      "column": "left",
      "text": "Bet es siunu tawu Dsih-\nwokli/ un tawu Iseefchannu un\ntawu Ge-Eefchannu / un ką tu\nprett manni trakko."
    },
    {
      "n": 29,
      "column": "left",
      "text": "Tapebz tad / ką tawa\nTrakfochana prett mannim/ un\ntawa Wehliba preefsch mann-\nnahm Aufim irr nahkufi / tad\ntikfhu es sawu Makschkeri ta-\nwás Nahtis/ un sawus Lausch-\nnus tawą Mutte/ un likfchu tewi\natrakfak greestees pa to paschu\nZettu/ pa kurru tu efi nahzis."
    },
    {
      "n": 30,
      "column": "left",
      "text": "Un fchi buhs tew par\nSihini/ schai Gaddą ehd / kas\nsawa Wallą irr andsis/un ohtrą\nGaddą kas no ta atkaf isaug /\nbet trescha Gaddą fehjeet un\nptanjeet / un stahdajt Wihna-\nDahrsus / un ehdeet winna\nAugkus."
    },
    {
      "n": 31,
      "column": "left",
      "text": "Jo tee Jeglahbtee / kas\nno ta Namna Juha irr atlik-\nkuschi / faknohs attat femmijup/\nun nessihs Augkus augschup."
    },
    {
      "n": 32,
      "column": "left",
      "text": "Jo no Jerusaleines isees\ntee/ kas irr atlikkuschi / un tee\nJeglahbtee no Zianas Kalna.\nScho darrihs ta karsta Dutino-\ntchana ta KUNGA."
    },
    {
      "n": 33,
      "column": "left",
      "text": "Tadeht ta fakfa tas\nKUNGS no ta Rehnina no\nAirtjas: Winsch ne nahkschai\nusfahta/ un ne schaus nievee."
    },
    {
      "n": 27,
      "column": "right",
      "text": "nu Bustu eeſch ta/ wiſch a\nar nekahdahm Preekſchtur-\nmahm Brukkahm prett win-\nnahks/ un ne uſmettihs pre-\nwinnu nekahdu Walli."
    },
    {
      "n": 34,
      "column": "right",
      "text": "Pa to Zettu/ fur win-\nnahzis/ buhs winnam atpak-\ngreestees/ bet schai Pilſtah-\nRUNGS:"
    },
    {
      "n": 35,
      "column": "right",
      "text": "Jo es paglabbaſchu ſch\nPilſſahtu / ka es to iſpetiju\nmannis deht/ un manna Kalp\nDahwida deht."
    },
    {
      "n": 36,
      "column": "right",
      "text": "Tad isgahje ta KUNg\nEngelis/ un kaue eeſch to Affi\nrexi Lehgera/ ſints aſtondefinit\nun peeſ tubkſtoschus. Un kad te-\nagri zehlahs/ tad bija tur wiſ-\nMirrouu pilns."
    },
    {
      "n": 37,
      "column": "right",
      "text": "Ta aigahje Saneribe\ntas Rehniſsch no Affirijas / uu\ngahje nohſt/ un greeseſs atpak-\nkaſ/ un palikke eeſch Ninives."
    },
    {
      "n": 38,
      "column": "right",
      "text": "Un kad wiſch eeſch Niſ-\nroka sawa Deewa Nanna pee-\nluhdſe/ tad nokawe winnu Adra-\nmeleſs un Sar Eezers winna\nDehti ar Sohbina/ bet tee ats-\nbehdſe us to Semmi Ararak.\nUn winna Dehis Affaraddons\ntappe par Rehnizu winna Weeta."
    }
  ],
  "confidence": "high",
